index e1923a344179..0e6074af128c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3506,6 +3506,48 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return BinaryOperator::CreateMul(X, IncrementY);
   }

+  // Fold (X / C) << K | (X % C) -> X + (X / C) * ((1 << K) - C)
+  // Fold (X / C) * K | (X % C) -> X + (X / C) * (K - C)
+  // because X = (X / C) * C + (X % C), so (X % C) = X - (X / C) * C
+  // This is a strength reduction when K != C.
+  {
+    Value *MulOrShl = Op0, *RemOp = Op1;
+    Value *X1, *X2, *DivOp;
+    APInt DivC, RemC, MulC;
+    const APInt *AI;
+    // Try to match rem on RHS, mul/shl on LHS; if not, try swapping
+    // Match URem first
+    if (!match(RemOp, m_URem(m_Value(X2), m_APInt(AI)))) {
+      std::swap(MulOrShl, RemOp);
+    }
+    if (match(RemOp, m_URem(m_Value(X2), m_APInt(AI)))) {
+      RemC = *AI;
+      // Match mul or shl on the other operand
+      bool MatchedMul = false;
+      if (match(MulOrShl, m_Mul(m_Value(DivOp), m_APInt(AI)))) {
+        MulC = *AI;
+        MatchedMul = true;
+      } else if (match(MulOrShl, m_Shl(m_Value(DivOp), m_APInt(AI)))) {
+        MulC = APInt(AI->getBitWidth(), 1);
+        MulC <<= *AI;
+        MatchedMul = true;
+      }
+      if (MatchedMul) {
+        // Check if DivOp is (X / C) with same X and C as Rem
+        if (match(DivOp, m_UDiv(m_Value(X1), m_APInt(AI))) &&
+            X1 == X2 && *AI == RemC) {
+          // Calculate K - C
+          APInt Diff = MulC - RemC;
+          Value *NewMul = Builder.CreateMul(DivOp, ConstantInt::get(I.getType(), Diff));
+          // The original mul/shl should have nuw because it's shifting/dividing
+          if (auto *BO = dyn_cast<BinaryOperator>(NewMul))
+            BO->setHasNoUnsignedWrap(true);
+          return BinaryOperator::CreateAdd(X1, NewMul);
+        }
+      }
+    }
+  }
+
   // (A & C) | (B & D)
   Value *A, *B, *C, *D;
   if (match(Op0, m_And(m_Value(A), m_Value(C))) &&

log.expect_optimized_program:
